#!/usr/bin/env python3
"""
Fix template concise answers in questions.js by replacing them with real, substantive content.

Two categories:
  Category A: Entries with template concise answers but real modelAnswer (175 questions)
  Category B: "Fundamental Question X" entries with fully template content (80 questions)

Approach: For each entry that needs fixing, match to pre-written real finance content
keyed by (role + base_topic + category_type).
"""

import re
import json
import sys

# ─── CONTENT MAP ─────────────────────────────────────────────────────────────
# Key: (role, base_topic) → dict of answer_by_category
# category_type can be: technical, behavioral, conceptual, practical

ANSWERS = {}

def reg(role, topic, **kwargs):
    """Register answers for a role+topic combination."""
    key = (role, topic)
    if key not in ANSWERS:
        ANSWERS[key] = {}
    for cat_type, answer in kwargs.items():
        ANSWERS[key][cat_type] = answer
    # Set a default answer if not all types are provided
    all_types = ['technical', 'behavioral', 'conceptual', 'practical']
    for t in all_types:
        if t not in ANSWERS[key]:
            # Use the first answer we have as fallback
            for v in ANSWERS[key].values():
                ANSWERS[key][t] = v
                break

