#  MAIN PROCESSING LOGIC
# ═══════════════════════════════════════════════════════════════════════════════

def js_escape(text):
    """Escape string for embedding in JS string literal."""
    text = text.replace('\\', '\\\\')
    text = text.replace('"', '\\"')
    text = text.replace('\n', '\\n')
    text = text.replace('\r', '\\r')
    text = text.replace('\t', '\\t')
    return text

def get_answer(block):
    """Get the correct concise answer for this entry, or None if no fix needed."""
    # Extract metadata
    title_m = re.search(r'"title":\s*"([^"]*)"', block)
    role_m = re.search(r'"role":\s*"([^"]*)"', block)
    cat_m = re.search(r'"category":\s*"([^"]*)"', block)
    
    if not title_m or not role_m:
        return None
    
    title = title_m.group(1)
    role = role_m.group(1)
    category = cat_m.group(1) if cat_m else "technical"
    
    is_fundamental = 'This is a fundamental question' in block
    is_template = bool(re.search(r'provide a (precise definition|direct[\s,])', block, re.IGNORECASE))
    
    # Also check for "First concept definition" template
    has_first_concept = bool(re.search(r'First concept definition', block))
    
    # Only process questions that need fixing
    if not is_fundamental and not is_template and not has_first_concept:
        return None
    
    # Handle Category B: Fundamental questions
    if is_fundamental:
        # Extract title number from "Fundamental Question X"
        num_m = re.search(r'Fundamental Question\s+(\d+)', title)
        if num_m:
            qnum = int(num_m.group(1))
            key = (role, qnum)
            if key in FUNDAMENTAL_ANSWERS:
                return FUNDAMENTAL_ANSWERS[key]
            print(f"  WARNING: No answer for {role} Fundamental Question {qnum}")
            return None
        return None
    
    # Handle Category A: template concise questions
    # Extract base topic from title (e.g., "Portfolio Construction & Optimization - Technical Question")
    base = title.split(' - ')[0] if ' - ' in title else title
    
    key = (role, base)
    if key in ANSWERS:
        answers_for_key = ANSWERS[key]
        # Choose answer based on category
        if category in answers_for_key:
            return answers_for_key[category]
        # Fallback: use any answer
        for v in answers_for_key.values():
            return v
        return None
    else:
        # Try with part of the title
        print(f"  WARNING: No answer for {role} → {base} (cat={category})")
        return None

def process_file(filepath):
    """Main processing function."""
    with open(filepath, 'r', encoding='utf-8') as f:
        content = f.read()
    
    start = content.index('const questionBank = [')
    rest = content[start:]
    
    # Find all question positions
    positions = [m.start() for m in re.finditer(r'\{\s*\n\s*"id":', rest)]
    
    print(f"Found {len(positions)} total question entries")
    
    stats = {"cat_a": 0, "cat_b": 0, "fixed": 0, "skipped": 0, "warnings": []}
    
    # Process from end to start to preserve positions
    # We'll build modified content by replacing blocks
    modifiers = []  # (start_pos, end_pos, new_block)
    
    for i, pos in enumerate(positions):
        if i + 1 < len(positions):
            block = rest[pos:positions[i+1]]
        else:
            block = rest[pos:]
            # Remove trailing ]; if present
            block = re.sub(r'\];?\s*$', '', block.rstrip())
        
        answer = get_answer(block)
        if answer is None:
            stats['skipped'] += 1
            continue
        
        # Determine category
        is_fundamental = 'This is a fundamental question' in block
        if is_fundamental:
            stats['cat_b'] += 1
        else:
            stats['cat_a'] += 1
        stats['fixed'] += 1
        
        # Escape the answer for JavaScript
        escaped_answer = js_escape(answer)
        
        # Find the concise answer field and replace it
        # Pattern: "answer": "old_template_content"
        old_concise_match = re.search(r'"answer"\s*:\s*"((?:[^"\\]|\\.)*?)"', block)
        if not old_concise_match:
            stats['warnings'].append(f'No concise answer found in block {i}')
            continue
        
        old_concise = old_concise_match.group(0)
        new_concise = '"answer": "' + escaped_answer + '"'
        
        # Create new block with replaced answer
        new_block = block.replace(old_concise, new_concise)
        
        # Record the modification (from end to keep positions valid)
        abs_pos = start + pos
        if i + 1 < len(positions):
            abs_end = start + positions[i+1]
        else:
            abs_end = len(content)
        
        modifiers.append((abs_pos, abs_end, new_block))
    
    # Apply modifications from end to start
    content_parts = []
    last_end = 0
    # Sort by start position descending to process from end
    modifiers.sort(key=lambda x: x[0], reverse=True)
    
    for mod_pos, mod_end, new_block in reversed(modifiers):
        content_parts.append(content[last_end:mod_pos])
        content_parts.append(new_block)
        last_end = mod_end
    content_parts.append(content[last_end:])
    
    new_content = ''.join(content_parts)
    
    # Validation
    if 'provide a precise definition' in new_content or 'provide a direct, structured' in new_content:
        remaining = (content.count('provide a precise definition') + content.count('provide a direct, structured'))
        remaining_expected = 678 - stats['fixed']  # non-fixed entries
        print(f'\nWARNING: Template answers may still remain')
    
    # Write output
    with open(filepath, 'w', encoding='utf-8') as f:
        f.write(new_content)
    
    print(f'\n=== RESULTS ===')
    print(f'Category A entries processed: {stats["cat_a"]}')
    print(f'Category B entries processed: {stats["cat_b"]}')
    print(f'Total fixed: {stats["fixed"]}')
    print(f'Skipped (no matching answer): {stats["skipped"]}')
    if stats['warnings']:
        print(f'Warnings:')
        for w in stats['warnings'][:10]:
            print(f'  {w}')


if __name__ == '__main__':
    import sys
    filepath = sys.argv[1] if len(sys.argv) > 1 else 'questions.js'
    print(f'Processing {filepath}...')
    process_file(filepath)
    print('Done!')